package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.File;
import java.io.FileOutputStream;
import java.io.IOException;
import java.nio.charset.Charset;

import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVPrinter;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVFormatPrintTest {

    private CSVFormat csvFormat;
    private File tempFile;

    @BeforeEach
    void setup() throws IOException {
        csvFormat = CSVFormat.DEFAULT;
        tempFile = File.createTempFile("csvformattest", ".csv");
        tempFile.deleteOnExit();
    }

    @Test
    void testPrint_withValidFileAndCharset() throws IOException {
        Charset charset = Charset.forName("UTF-8");
        CSVPrinter printer = csvFormat.print(tempFile, charset);
        assertNotNull(printer);
        printer.close();
    }

    @Test
    void testPrint_withDifferentCharset() throws IOException {
        Charset charset = Charset.forName("ISO-8859-1");
        CSVPrinter printer = csvFormat.print(tempFile, charset);
        assertNotNull(printer);
        printer.close();
    }

    @Test
    void testPrint_withCustomCSVFormat() throws IOException {
        CSVFormat customFormat = CSVFormat.DEFAULT.withDelimiter(';').withQuote('\'').withRecordSeparator("\n");
        CSVPrinter printer = customFormat.print(tempFile, Charset.defaultCharset());
        assertNotNull(printer);
        printer.close();
    }

    @Test
    void testPrint_throwsIOExceptionWhenFileCannotBeWritten() throws Exception {
        File mockFile = mock(File.class);
        Charset charset = Charset.defaultCharset();

        // Use reflection to replace FileOutputStream constructor to throw IOException when called with mockFile
        // This requires a custom SecurityManager or a library like PowerMock, but since only Mockito 3 is allowed,
        // we simulate by creating a temp file and setting it read-only to cause IOException on FileOutputStream.

        File readOnlyFile = File.createTempFile("readonly", ".csv");
        readOnlyFile.deleteOnExit();
        boolean setReadOnly = readOnlyFile.setReadOnly();
        assertTrue(setReadOnly, "Failed to set file to read-only, test may not behave as expected");

        try {
            csvFormat.print(readOnlyFile, charset);
            fail("Expected IOException");
        } catch (IOException e) {
            // Expected exception
        }
    }
}
